onClick:
{{
  (async () => {
    try {
      const result = await InsertPartner.run();

      const partnerId =
        result?.insertId ||
        result?.[0]?.insertId ||
        InsertPartner.data?.insertId ||
        InsertPartner.data?.[0]?.insertId ||
        PartnerNameInput.text;

      await AuditLog1.insert({
        entityName: "business_partners",
        entityId: String(partnerId),
        actionType: "INSERT",
        newValues: {
          source: "POS / Invoice quick add",
          code: PartnerCodeInput.text,
          name: PartnerNameInput.text,
          legal_name: LegalNameInput.text,
          oib: OIBInput.text,
          registration_number: RegistrationNumberInput.text,
          address_line1: AddressInput.text,
          city: CityInput.text,
          postal_code: PostalCodeInput.text,
          email: Email.text,
          phone: Phone.text,
          payment_term_days: PaymentTermDaysInput.text,
          credit_limit: PaymentTermDays.text,
          note: Note.text
        }
      });

      showAlert("Partner saved.", "success");

      await storeValue("partnerAutofill", {});

      OIBInput.setValue("");
      PartnerCodeInput.setValue("");
      PartnerNameInput.setValue("");
      LegalNameInput.setValue("");
      RegistrationNumberInput.setValue("");
      AddressInput.setValue("");
      CityInput.setValue("");
      PostalCodeInput.setValue("");
      Email.setValue("");
      Phone.setValue("");
      PaymentTermDaysInput.setValue("");
      PaymentTermDays.setValue("");
      Note.setValue("");

      resetWidget("PartnerTypeSelect", true);
      resetWidget("CountryCodeSelect", true);

      closeModal("PartnerModal");

      if (typeof InsertAuditLog !== "undefined") {
        await InsertAuditLog.run();
      }
    } catch (error) {
      showAlert("Partner could not be saved: " + error.message, "error");
      console.log(error);
    }
  })()
}}
